#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int K;
        scanf("%d", &K);
        char S[101];
        scanf("%s", S);
        int N = strlen(S);
        for (int i = 0; i < N; i++) {
            if (S[i] == '?') {
                for (int j = 0; j < K; j++) {
                    S[i] = '0' + j;
                    int valid = 1;
                    for (int k = 0; k < N; k++) {
                        if (k > 0 && S[k] == S[k - 1]) {
                            valid = 0;
                            break;
                        }
                        if (k < N - 1 && S[k] == S[k + 1]) {
                            valid = 0;
                            break;
                        }
                        if (k == 0 && N > 1 && S[k] == S[N - 1]) {
                            valid = 0;
                            break;
                        }
                    }
                    if (valid) {
                        break;
                    }
                }
            }
        }
        int valid = 1;
        for (int i = 0; i < N; i++) {
            if (S[i] == '?') {
                valid = 0;
                break;
            }
        }
        if (valid) {
            printf("%s\n", S);
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

